var sumDivisibleByK = function(nums, k) {
    const freq = new Map();
    for (const v of nums) freq.set(v, (freq.get(v) || 0) + 1);
    let total = 0;
    for (const [v, c] of freq) {
        if (c % k === 0) total += v * c;
    }
    return total;
};
